COLORS = ["#d44638","#1a73e8","#34a853","#f4511e","#9c27b0","#0b8043"]
def card(i, name, text, meta="Отзыв в Facebook", date="рекомендует", fb="https://www.facebook.com/LuxxAed/reviews", more="Смотреть в Facebook →"):
    c=COLORS[i%len(COLORS)]; l=name.strip()[0]
    return (f'<div class="gbp-rev-card"><div class="gbp-rev-top"><div class="ava" style="background:{c}">{l}</div>'
            f'<div><div class="gr-name">{name}</div><div class="gr-meta">{meta}</div></div></div>'
            f'<div class="gbp-rev-stars-row">★★★★★ <span class="gbp-rev-date">{date}</span></div>'
            f'<p class="gbp-rev-txt">{text}</p>'
            f'<a class="gbp-rev-more" href="{fb}" target="_blank" rel="noopener">{more}</a></div>')
